#!/usr/bin/env python3
"""
LFE v2 Scaffold Installer for AutoResearchClaw

Run this script from the root of your AutoResearchClaw clone:
    python3 apply_lfe_scaffold.py

Then commit and push:
    git add .
    git commit -m "feat(lfe): scaffold Library-First Engineering v2 framework"
    git push
"""
import os, base64

FILES = {
    '.agents/adapters/cursor/.cursorrules': '',
    '.agents/adapters/system_prompt.txt': '',
    '.agents/skills/lfe-architect/SKILL.md': '',
    '.agents/skills/lfe-archivist/SKILL.md': '',
    '.agents/skills/lfe-boot/SKILL.md': '',
    '.agents/skills/lfe-builder/SKILL.md': '',
    '.agents/skills/lfe-diagnose/SKILL.md': '',
    '.agents/skills/lfe-extract-domain/SKILL.md': '',
    '.agents/skills/lfe-grill-me/SKILL.md': '',
    '.agents/skills/lfe-grill-with-docs/ADR-FORMAT.md': '',
    '.agents/skills/lfe-grill-with-docs/CONTEXT-FORMAT.md': '',
    '.agents/skills/lfe-grill-with-docs/SKILL.md': '',
    '.agents/skills/lfe-hygiene/SKILL.md': '',
    '.agents/skills/lfe-improve-architecture/INTERFACE-DESIGN.md': '',
    '.agents/skills/lfe-improve-architecture/LANGUAGE.md': '',
    '.agents/skills/lfe-improve-architecture/SKILL.md': '',
    '.agents/skills/lfe-inspector/SKILL.md': '',
    '.agents/skills/lfe-scout/SKILL.md': '',
    '.agents/skills/lfe-tdd/SKILL.md': '',
    '.agents/skills/lfe-tdd/deep-modules.md': '',
    '.agents/skills/lfe-tdd/interface-design.md': '',
    '.agents/skills/lfe-tdd/mocking.md': '',
    '.agents/skills/lfe-tdd/refactoring.md': '',
    '.agents/skills/lfe-tdd/tests.md': '',
    '.agents/skills/lfe-to-issues/SKILL.md': '',
    '.agents/skills/lfe-to-prd/SKILL.md': '',
    '.agents/skills/lfe-whats-next/SKILL.md': '',
    '.agents/skills/lfe-zoom-out/SKILL.md': '',
    '.antigravityrules': '',
    '.clinerules': '',
    '.docs/README.md': '',
    '.docs/architecture/architecture-decisions.md': '',
    '.docs/architecture/engineering-standards.md': '',
    '.docs/archive/changelog-history.md': '',
    '.docs/domain/domain-knowledge.md': '',
    '.docs/domain/glossary.md': '',
    '.docs/legal/privacy-policy.md': 'IyBQcml2YWN5IFBvbGljeQoKRGVmaW5lIGhvdyB5b3VyIHByb2plY3QgaGFuZGxlcyBkYXRhIGFuZCB1c2VyIHByaXZhY3kuCg==',
    '.docs/protocol/ASSEMBLY_LINE.md': '',
    '.docs/protocol/GOVERNANCE.md': '',
    '.docs/protocol/INDUSTRY_STANDARDS.md': '',
    '.docs/protocol/PERSONAS.md': '',
    '.docs/quality/CHANGELOG.md': '',
    '.docs/quality/PROTOCOL_DEBT.md': '',
    '.docs/quality/known-issues.md': '',
    '.docs/strategy/roadmap.md': '',
    '.windsurfrules': '',
    'CONTEXT.md': '',
    'pipeline_status.md': '',
}

def main():
    root = os.getcwd()
    created = []
    for rel_path, b64_content in FILES.items():
        full_path = os.path.join(root, rel_path)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        content = base64.b64decode(b64_content.encode("ascii"))
        with open(full_path, "wb") as f:
            f.write(content)
        created.append(rel_path)
        print(f"  ✓ {rel_path}")
    print(f"\nCreated {len(created)} files.")
    print("\nNext steps:")
    print("  git add .")
    print('  git commit -m \"feat(lfe): scaffold Library-First Engineering v2 framework\"',)
    print("  git push")

if __name__ == "__main__":
    main()
